              />
          </div>

          <div className="flex-grow">
              {filteredProducts.length === 0 ? (
                  <div className="flex flex-col items-center justify-center h-64 text-gray-300">
                      <i className="fas fa-box-open text-4xl mb-3 opacity-20"></i>
                      <p className="text-sm font-medium">Kho hàng trống</p>
                  </div>
              ) : (
                  <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-4 gap-4">
                      {filteredProducts.map(p => {
                          const total = p.totalImported || p.stockQuantity || 1;
                          const sold = Math.max(0, total - (p.stockQuantity || 0));
                          const percent = Math.min(100, (p.stockQuantity / total) * 100);
                          const isLow = p.stockQuantity < 5;

                          return (
                              <div key={p.id} onClick={() => handleViewDetail(p)} className="bg-white border border-gray-100 rounded-2xl p-3 shadow-sm hover:shadow-md hover:border-blue-200 transition-all cursor-pointer relative group flex flex-col justify-between">
                                  {/* Header: Name + Edit */}
                                  <div className="flex justify-between items-start mb-2">
                                      <h3 className="font-bold text-sm text-gray-800 line-clamp-2 flex-grow mr-2" title={p.name}>
                                          {p.name}
                                      </h3>
                                      <button 
                                          onClick={(e) => { e.stopPropagation(); handleEdit(p); }}
                                          className="text-gray-300 hover:text-blue-600 transition-colors p-1"
                                      >
                                          <i className="fas fa-pen text-xs"></i>
                                      </button>
                                  </div>

                                  {/* Big Stock Number */}
                                  <div className="flex items-center justify-center my-3 relative">
                                       <div className={`text-4xl font-black ${isLow ? 'text-red-500 animate-pulse' : 'text-gray-800'}`}>
                                           {p.stockQuantity}
                                       </div>
                                       {/* Progress Bar Background */}
                                       <div className="absolute bottom-[-8px] left-2 right-2 h-1.5 bg-gray-100 rounded-full overflow-hidden">
                                            <div 
                                                className={`h-full rounded-full transition-all duration-500 ${isLow ? 'bg-red-500' : 'bg-eco-500'}`} 
                                                style={{ width: `${percent}%` }}
                                            ></div>
                                       </div>
                                  </div>

                                  {/* Mini Stats Grid */}
                                  <div className="grid grid-cols-3 gap-1 mt-4 text-center">
                                      <div className="bg-blue-50 rounded-lg py-1.5 px-1">
                                          <div className="text-[9px] text-blue-400 font-bold uppercase">Giá Bán</div>
                                          <div className="text-xs font-bold text-blue-700 truncate">{new Intl.NumberFormat('vi-VN', { notation: "compact" }).format(p.defaultPrice)}</div>
                                      </div>
                                      <div className="bg-orange-50 rounded-lg py-1.5 px-1">
                                          <div className="text-[9px] text-orange-400 font-bold uppercase">Đã Bán</div>
                                          <div className="text-xs font-bold text-orange-700">{sold}</div>
                                      </div>
                                      <div className="bg-gray-100 rounded-lg py-1.5 px-1">
                                          <div className="text-[9px] text-gray-400 font-bold uppercase">Tổng</div>
                                          <div className="text-xs font-bold text-gray-600">{total}</div>
                                      </div>
                                  </div>

                                  {/* Quick Add Button */}
                                  <button 
                                      onClick={(e) => handleQuickStock(e, p, 1)}
                                      className="absolute top-1/2 -right-3 transform -translate-y-1/2 w-8 h-8 bg-white border border-gray-100 rounded-full shadow-md flex items-center justify-center text-eco-600 hover:bg-eco-50 hover:scale-110 transition-all opacity-0 group-hover:opacity-100 group-hover:right-[-10px]"
                                      title="Nhập nhanh +1"
                                  >
                                      <i className="fas fa-plus text-xs"></i>
                                  </button>
                              </div>
                          );
                      })}
                  </div>
              )}
          </div>
      </div>

      {/* DETAIL MODAL */}
      {viewingProduct && (
          <ProductDetailModal 
            isOpen={!!viewingProduct}
            onClose={() => setViewingProduct(null)}
            product={viewingProduct}
            onImport={() => {
                handleEdit(viewingProduct);
                setViewingProduct(null);
            }}
            onAdjust={() => {
                handleAdjust(viewingProduct);
                setViewingProduct(null);
            }}
            onDelete={handleDeleteFromDetail}
          />
      )}

      {/* ADD/EDIT FORM MODAL */}
      <ProductEditModal 
          isOpen={showProductModal}
          onClose={() => setShowProductModal(false)}
          product={editingProduct}
          onSave={handleSaveProduct}
          initialMode={editMode}
      />

      <ConfirmModal 
        isOpen={showDeleteConfirm}
        title="Xóa sản phẩm?"
        message="Sản phẩm sẽ bị xóa vĩnh viễn khỏi kho."
        onConfirm={confirmDelete}
        onCancel={() => setShowDeleteConfirm(false)}
        confirmLabel="Xóa"
        isDanger={true}
      />
      <ConfirmModal 
        isOpen={showSyncConfirm}
        title="Đồng bộ giá?"
        message="Bạn có muốn cập nhật tên & giá mới cho các đơn hàng ĐANG XỬ LÝ không?"
        onConfirm={handleConfirmSync}
        onCancel={() => { setShowSyncConfirm(false); setShowProductModal(false); }}
        confirmLabel="Đồng bộ ngay"
        cancelLabel="Không, chỉ lưu kho"
        isDanger={false}
      />
    </div>
  );
};

export default InventoryManager;
