      {/* CONFIRM MODAL */}
      <ConfirmModal 
        isOpen={confirmData.isOpen}
        title="Xác nhận thanh toán"
        message={confirmData.message}
        onConfirm={executeConfirm}
        onCancel={() => setConfirmData({ ...confirmData, isOpen: false })}
        confirmLabel="Tiền đã về"
        isDanger={false}
      />
    </div>
  );
};

